import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { environment } from '../../environments/environment';

@Injectable({ providedIn: 'root' })
export class ApiService {
  private readonly routeToService: Record<string, keyof typeof environment.microservices.services> = {
    '/auth': 'auth',
    '/users': 'users',
    '/admin': 'admin',
    '/leaves': 'leaves',
    '/goals': 'goals',
    '/performance': 'performance'
  };

  constructor(private http: HttpClient) {}

  get<T>(path: string): Observable<T> { return this.http.get<T>(this.buildUrl(path)); }
  post<T>(path: string, body: unknown): Observable<T> { return this.http.post<T>(this.buildUrl(path), body); }
  put<T>(path: string, body: unknown): Observable<T> { return this.http.put<T>(this.buildUrl(path), body); }
  patch<T>(path: string, body: unknown): Observable<T> { return this.http.patch<T>(this.buildUrl(path), body); }
  delete<T>(path: string): Observable<T> { return this.http.delete<T>(this.buildUrl(path)); }

  private buildUrl(path: string): string {
    if (environment.backendType === 'monolith') {
      return `${this.trimTrailingSlash(environment.apiBaseUrl)}${path}`;
    }

    const baseUrl = this.resolveMicroserviceBaseUrl(path);
    return `${this.trimTrailingSlash(baseUrl)}${path}`;
  }

  private resolveMicroserviceBaseUrl(path: string): string {
    const entry = Object.entries(this.routeToService).find(([prefix]) => path.startsWith(prefix));
    if (!entry) {
      return environment.microservices.defaultBaseUrl;
    }

    const serviceKey = entry[1];
    return environment.microservices.services[serviceKey] ?? environment.microservices.defaultBaseUrl;
  }

  private trimTrailingSlash(value: string): string {
    return value.endsWith('/') ? value.slice(0, -1) : value;
  }
}
